import api from "./app/client";
import type { Pagination } from "../types/api";

export interface LogEntry {
  id?: string;
  timestamp: string;
  level: string;
  message: string;
  exception?: string;
  sourceContext?: string;
  requestMethod?: string;
  requestPath?: string;
  statusCode?: string;
  correlationId?: string;
  userEmail?: string;
  userRole?: string;
  clientIp?: string;
  machineName?: string;
  environmentName?: string;
  [key: string]: unknown;
}

export interface GetLogsParams {
  search?: string;
  level?: string;
  timeRange?: string;
  sort?: string;
  sortOrder?: 'Ascending' | 'Descending';
  pageIndex?: number;
  pageSize?: number;
}

export const logService = {
  getLogs: async (params?: GetLogsParams): Promise<Pagination<LogEntry>> => {
    const response = await api.get('/admin/logs', { params });
    return response.data;
  },
};
