import { Button } from "@/shadcn/components/ui/button";
import { logService } from "@/api/logService";
import type { LogEntry } from "@/api/logService";
import { HarmonyTable, type HarmonyColumn } from "@/components/ui/harmony-table";
import HarmonyForm, { type FormSchema } from "@/components/forms/HarmonyForm";
import { useHarmonyServerTable } from "@/hooks/useHarmonyServerTable";
import { Badge } from "@/shadcn/components/ui/badge";
