import { queryKeys } from "@/lib/queryKeys";

interface LevelMeta {
  icon: React.ReactNode;
  badgeClass: string;
}

function getLevelMeta(level: string): LevelMeta {
  const l = (level || "").toLowerCase();
  if (l === "fatal")
    return { icon: <XCircle size={11} />,      badgeClass: "border-red-300 bg-red-50 text-red-700 dark:border-red-800 dark:bg-red-950/40 dark:text-red-300" };
  if (l === "error")
    return { icon: <AlertCircle size={11} />,   badgeClass: "border-destructive/40 bg-destructive/10 text-destructive" };
  if (l === "warning" || l === "warn")
    return { icon: <AlertTriangle size={11} />, badgeClass: "border-amber-300 bg-amber-50 text-amber-700 dark:border-amber-700 dark:bg-amber-950/40 dark:text-amber-400" };
  if (l === "information" || l === "info")
    return { icon: <Info size={11} />,          badgeClass: "border-primary/30 bg-primary/10 text-primary" };
  if (l === "debug")
    return { icon: <Bug size={11} />,           badgeClass: "border-sky-300 bg-sky-50 text-sky-700 dark:border-sky-700 dark:bg-sky-950/40 dark:text-sky-400" };
  return   { icon: <Info size={11} />,          badgeClass: "" };
}


