interface LogsFilters {
  level: string;
  timeRange: string;
  [key: string]: string;
}

function LogsHarmonyTable() {
  const server = useHarmonyServerTable<LogsFilters>({
    defaultFilters: { timeRange: 'last1day' },
  });

  const { data, isLoading, isFetching, refetch, isError, error } = useQuery({
    queryKey: queryKeys.logs.list(
      server.filterValues,
      server.sort,
      server.sortOrder,
      server.pageIndex,
      server.pageSize,
    ),
    queryFn: () =>
      logService.getLogs({
        level:     server.filterValues.level     || undefined,
        timeRange: server.filterValues.timeRange || undefined,
        sort:      server.sort,
        sortOrder: server.sortOrder,
        pageIndex: server.pageIndex,
        pageSize:  server.pageSize,
      }),
    refetchInterval: server.autoRefresh ? server.refreshInterval * 1000 : false,
  });

  return (
    <HarmonyTable<LogEntry>
      rows={data?.data ?? []}
      columns={logColumns}
      rowKeyGetter={(row) => row.id ?? ''}
      loading={isLoading}
      error={isError ? (error as Error) : undefined}

      filterDefs={[
        {
          param: 'level',
          label: 'Level',
          type: 'select',
          options: [
            { value: 'Information', label: 'Info' },
            { value: 'Warning',     label: 'Warning' },
            { value: 'Error',       label: 'Error' },
            { value: 'Debug',       label: 'Debug' },
            { value: 'Fatal',       label: 'Fatal' },
          ],
        },
        {
          param: 'timeRange',
          label: 'Period',
          type: 'select',
          defaultValue: 'last1day',
          options: [
            { value: 'last1hour',  label: 'Last 1 Hour' },
            { value: 'last8hours', label: 'Last 8 Hours' },
            { value: 'last1day',   label: 'Last 1 Day' },
            { value: 'last7days',  label: 'Last 7 Days' },
          ],
        },
      ]}
      filterValues={server.filterValues}
      onFilterChange={server.onFilterChange}

      sortColumns={server.sortColumns}
      onSortColumnsChange={server.onSortColumnsChange}

      searchPlaceholder="Search logs…"

      dataActions={{
        onReload:  () => refetch(),
        reloading: isFetching,
        autoRefresh: {
          enabled:          server.autoRefresh,
          interval:         server.refreshInterval,
          onToggle:         server.setAutoRefresh,
          onIntervalChange: server.setRefreshInterval,
        },
      }}

      selectable
      selectionActions={(selectedKeys) => {
        const selectedRows = (data?.data ?? []).filter(row => selectedKeys.has(row.id ?? ''));
        return (
          <Button
            variant="default"
            size="xs"
            onClick={() => {
              const blob = new Blob([JSON.stringify(selectedRows, null, 2)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url;
              a.download = `logs-selected-${selectedRows.length}.json`;
              a.click();
              URL.revokeObjectURL(url);
            }}
          >
            <Download size={12} />
            Export
          </Button>
        );
      }}

      exportable
      exportFilename={`logs-page${server.pageIndex}.json`}

      pagination={server.getPagination(data)}

      renderRowDetail={(row, onClose) => (
        <HarmonyForm
          schema={logEntryViewSchema}
          defaultValues={row}
          onSubmit={() => { onClose(); }}
          hideSubmitButton
        />
      )}
      rowDetailTitle={(row) => `Log — ${(row.level || "INFO").toUpperCase()}`}
      rowDetailVariant="sheet"
      rowDetailTrigger="click"

    />
  );
}

export default function Logs() {
  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>
      <div className="flex items-center gap-3">
        <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
          <ScrollText className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="page-title">System Logs</h1>
          <p className="page-subtitle">Real-time monitoring and historical backend activity.</p>
        </div>
      </div>

      <LogsHarmonyTable />
    </div>
  );
}
